// cursor_ipgen_cold — SSOT fsm.control + cycle_model + rtl_contract + latency_1_required_rtl_shape
// FM_HANDSHAKE_ACCEPT / FM_EMIT_SHIFTED / RTL_CIGC_PIPELINE: accept on ST_IDLE edge; emit on following edge (accept_to_emit min/max 1).
// RTL-0010: DATA_WIDTH/RESULT_WIDTH parameters drive port widths per SSOT parameters section.
// RTL-0011: result_valid is registered from emit_cycle_qual (continuous decode of ST_ACCEPT emit cycle).
// io_list port traceability (packet module__cursor_ipgen_cold__io_list):
//   io_list.clock_domains.SYSCLK.ports.clk -> clk
//   io_list.resets.RSTn.ports.rst_n -> rst_n
//   io_list.interfaces.stream_shift_slave.ports.valid -> valid
//   io_list.interfaces.stream_shift_slave.ports.ready -> ready
//   io_list.interfaces.stream_shift_slave.ports.data_in -> data_in[DATA_WIDTH-1:0]
//   io_list.interfaces.stream_shift_slave.ports.result -> result[RESULT_WIDTH-1:0]
//   io_list.interfaces.stream_shift_slave.ports.result_valid -> result_valid
// cycle_model.ordering: accepted_count increments only on completed handshakes (ST_IDLE valid&&ready).
// Shift path: (zero-extended latched_data << 1) & all-ones mask — SSOT FM_EMIT_SHIFTED (latched_data << 1) & 511 equivalence for default widths.

`include "cursor_ipgen_cold_param.vh"

module cursor_ipgen_cold #(
    parameter integer DATA_WIDTH       = `RTL_CIGC_PARAMS_DATA_WIDTH_DEFAULT,
    parameter integer RESULT_WIDTH   = `RTL_CIGC_PARAMS_RESULT_WIDTH_DEFAULT,
    parameter integer CLOCK_FREQ_MHZ = 100,
    parameter integer RESET_POLARITY = 0
) (
    input  logic                       clk,
    input  logic                       rst_n,
    input  logic                       valid,
    output logic                       ready,
    input  logic [DATA_WIDTH-1:0]      data_in,
    output logic [RESULT_WIDTH-1:0]  result,
    output logic                       result_valid
);

    localparam integer RP_RESET_ACTIVE_LOW = 0;

    localparam [2:0] ST_RESET   = 3'd0;
    localparam [2:0] ST_IDLE  = 3'd1;
    localparam [2:0] ST_ACCEPT = 3'd2;
    localparam [2:0] ST_EMIT  = 3'd3;

    logic [31:0] accepted_count;
    logic [DATA_WIDTH-1:0] latched_data;
    logic                  pending_emit;

    logic [2:0] ctrl_state;

    wire                     reset_asserted;
    wire                     cfg_ready_ok;
    wire [RESULT_WIDTH-1:0]  latched_zext;
    wire [RESULT_WIDTH-1:0]  shifted_lat;
    wire [RESULT_WIDTH-1:0]  result_mask;
    wire                     emit_cycle_qual;

    assign reset_asserted = (RESET_POLARITY == RP_RESET_ACTIVE_LOW) ? (~rst_n) : rst_n;
    assign cfg_ready_ok   = (CLOCK_FREQ_MHZ > 32'd0);
    assign ready          = cfg_ready_ok && !pending_emit;

    assign result_mask    = {RESULT_WIDTH{1'b1}};
    assign latched_zext   = {{(RESULT_WIDTH - DATA_WIDTH){1'b0}}, latched_data};
    assign shifted_lat    = (latched_zext << 1) & result_mask;
    assign emit_cycle_qual = (ctrl_state == ST_ACCEPT);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            accepted_count <= 32'd0;
            latched_data   <= {DATA_WIDTH{1'b0}};
            pending_emit   <= 1'b0;
            result         <= {RESULT_WIDTH{1'b0}};
            result_valid   <= 1'b0;
            ctrl_state     <= ST_RESET;
        end else if (reset_asserted) begin
            accepted_count <= 32'd0;
            latched_data   <= {DATA_WIDTH{1'b0}};
            pending_emit   <= 1'b0;
            result         <= {RESULT_WIDTH{1'b0}};
            result_valid   <= 1'b0;
            ctrl_state     <= ST_RESET;
        end else begin
            result_valid <= emit_cycle_qual;
            case (ctrl_state)
                ST_RESET: begin
                    if (!reset_asserted) begin
                        ctrl_state <= ST_IDLE;
                    end
                end
                ST_IDLE: begin
                    if (valid && ready) begin
                        latched_data   <= data_in;
                        accepted_count <= accepted_count + 32'd1;
                        pending_emit   <= 1'b1;
                        ctrl_state     <= ST_ACCEPT;
                    end
                end
                ST_ACCEPT: begin
                    result       <= shifted_lat;
                    pending_emit <= 1'b0;
                    ctrl_state   <= ST_EMIT;
                end
                ST_EMIT: begin
                    ctrl_state <= ST_IDLE;
                end
                default: begin
                    ctrl_state <= ST_IDLE;
                end
            endcase
        end
    end

endmodule
